contracts/AccidentDApp.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./RoleRegistry.sol";
import "./AccidentStorage.sol";

/**
 * @title  AccidentDApp
 * @notice Logique métier — orchestration du cycle de vie des accidents automobiles.
 *
 * @dev    Architecture modulaire à 3 couches :
 *
 *         ┌─────────────────────────────────────────────────────────┐
 *         │                     AccidentDApp                        │
 *         │           (Logique métier + validation)                 │
 *         └────────────────────┬────────────────────────────────────┘
 *                              │ lit les rôles      │ lit/écrit les données
 *                              ▼                    ▼
 *                     ┌───────────────┐   ┌──────────────────────┐
 *                     │ RoleRegistry  │   │  AccidentStorage     │
 *                     │ (Rôles)       │   │  (Données pures)     │
 *                     └───────────────┘   └──────────────────────┘
 *
 *         Principes :
 *         - Ce contrat ne stocke aucune donnée métier — tout va dans AccidentStorage
 *         - Les rôles sont gérés dans RoleRegistry — réutilisable par d'autres contrats
 *         - Seul ce contrat est autorisé à écrire dans AccidentStorage (setController)
 *         - En cas de bug ou évolution, on peut redéployer AccidentDApp et pointer le
 *           nouveau contrôleur sur l'AccidentStorage existant (données préservées)
 *
 *         Cycle de vie :
 *         Declared → Verification → Expertise → Validated / Rejected → Closed
 */
contract AccidentDApp {

    // ─────────────────────────────────────────────────────────────────────────
    // RÉFÉRENCES AUX CONTRATS DÉPENDANTS
    // ─────────────────────────────────────────────────────────────────────────

    /// @notice Registre des rôles — source de vérité pour les autorisations
    RoleRegistry    public roleRegistry;

    /// @notice Stockage des dossiers — source de vérité pour les données
    AccidentStorage public accidentStorage;

    /// @notice Adresse de l'administrateur (déployeur)
    address public owner;

    // ─────────────────────────────────────────────────────────────────────────
    // CONSTANTES DE RÔLES — mises en cache pour éviter les appels externes
    // dans les modificateurs (réduit la profondeur de call stack)
    // ─────────────────────────────────────────────────────────────────────────

    bytes32 public immutable ROLE_DRIVER;
    bytes32 public immutable ROLE_EXPERT;
    bytes32 public immutable ROLE_INSURER;

    // ─────────────────────────────────────────────────────────────────────────
    // ÉVÉNEMENTS
    // ─────────────────────────────────────────────────────────────────────────

    /// @notice Émis à chaque nouvelle déclaration d'accident
    event AccidentDeclared(
        uint256 indexed id,
        address indexed driver,
        string evidenceHash,
        string evidenceCID,
        uint256 timestamp
    );

    /// @notice Émis quand un expert est assigné (par l'assureur ou en auto-assignation)
    event ExpertAssigned(uint256 indexed id, address indexed expert, address indexed insurer);

    /// @notice Émis quand l'expert soumet son rapport
    event ReportSubmitted(uint256 indexed id, address indexed expert, string reportHash, string reportCID);

    /// @notice Émis quand l'assureur valide un dossier
    event AccidentValidated(uint256 indexed id, address indexed insurer);

    /// @notice Émis quand l'assureur rejette un dossier
    event AccidentRejected(uint256 indexed id, address indexed insurer, string reason);

    /// @notice Émis quand l'owner clôture un dossier validé
    event AccidentClosed(uint256 indexed id);

    // ─────────────────────────────────────────────────────────────────────────
    // MODIFICATEURS
    // ─────────────────────────────────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "AccidentDApp: not owner");
        _;
    }

    /**
     * @dev Délègue la vérification de rôle à RoleRegistry.hasRole().
     *      Vérifie à la fois le rôle ET le statut actif (non révoqué).
     */
    modifier onlyRole(bytes32 role) {
        require(
            roleRegistry.hasRole(msg.sender, role),
            "AccidentDApp: unauthorized role"
        );
        _;
    }

    /**
     * @dev Délègue la vérification d'existence à AccidentStorage.exists().
     */
    modifier accidentExists(uint256 id) {
        require(accidentStorage.exists(id), "AccidentDApp: accident not found");
        _;
    }

    /**
     * @dev Délègue la vérification de statut à AccidentStorage.getStatus().
     *      Empêche les transitions illégales dans le cycle de vie.
     */
    modifier inStatus(uint256 id, AccidentStorage.Status expected) {
        require(
            accidentStorage.getStatus(id) == expected,
            "AccidentDApp: invalid status for this action"
        );
        _;
    }

    /**
     * @dev Valide un hash SHA-256 :
     *      - Exactement 64 caractères
     *      - Uniquement des chiffres (0-9) et lettres minuscules (a-f)
     *      Empêche le stockage de données arbitraires.
     */
    modifier validHash(string calldata h) {
        bytes memory b = bytes(h);
        require(b.length == 64, "AccidentDApp: hash must be 64 hex chars (SHA-256)");
        for (uint256 i = 0; i < 64; i++) {
            bytes1 c = b[i];
            require(
                (c >= 0x30 && c <= 0x39) || (c >= 0x61 && c <= 0x66),
                "AccidentDApp: hash must be lowercase hex"
            );
        }
        _;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // CONSTRUCTEUR
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice Déploie le contrat en le liant aux deux contrats de couche inférieure.
     *
     * @dev    Après le déploiement, appeler AccidentStorage.setController(address(this))
     *         pour autoriser ce contrat à écrire dans le stockage.
     *
     * @param  _roleRegistry      Adresse du contrat RoleRegistry déployé
     * @param  _accidentStorage   Adresse du contrat AccidentStorage déployé
     */
    constructor(address _roleRegistry, address _accidentStorage) {
        require(_roleRegistry    != address(0), "AccidentDApp: invalid RoleRegistry address");
        require(_accidentStorage != address(0), "AccidentDApp: invalid AccidentStorage address");

        owner            = msg.sender;
        roleRegistry     = RoleRegistry(_roleRegistry);
        accidentStorage  = AccidentStorage(_accidentStorage);

        // Mise en cache des constantes de rôles — une seule lecture externe au déploiement
        // Élimine 1 appel externe par modificateur onlyRole → réduit la profondeur de call stack
        ROLE_DRIVER  = RoleRegistry(_roleRegistry).ROLE_DRIVER();
        ROLE_EXPERT  = RoleRegistry(_roleRegistry).ROLE_EXPERT();
        ROLE_INSURER = RoleRegistry(_roleRegistry).ROLE_INSURER();
    }

    // ─────────────────────────────────────────────────────────────────────────
    // DÉCLARATION D'ACCIDENT
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice Le conducteur déclare un accident en soumettant les preuves.
     *         La transaction est signée par son wallet MetaMask — il est l'auteur prouvé.
     *
     * @dev    Seul un conducteur enregistré (ROLE_DRIVER) peut appeler cette fonction.
     *         Le hash doit être un SHA-256 valide (64 chars hex minuscules).
     *         driverSigned est mis à true automatiquement (signature MetaMask implicite).
     *
     * @param  evidenceHash  SHA-256 des photos/preuves calculé côté frontend
     * @param  evidenceCID   CID IPFS des preuves (vide si IPFS désactivé)
     * @param  location      Lieu de l'accident
     * @return               ID du dossier créé
     */
    function declareAccident(
        string calldata evidenceHash,
        string calldata evidenceCID,
        string calldata location
    )
        external
        onlyRole(ROLE_DRIVER)
        validHash(evidenceHash)
        returns (uint256)
    {
        require(bytes(location).length > 0, "AccidentDApp: location required");

        uint256 id = accidentStorage.createAccident(
            msg.sender,
            evidenceHash,
            evidenceCID,
            location
        );

        emit AccidentDeclared(id, msg.sender, evidenceHash, evidenceCID, block.timestamp);
        return id;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // ASSIGNATION DE L'EXPERT
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice L'assureur assigne un expert à un dossier déclaré.
     *
     * @dev    Seul un assureur enregistré (ROLE_INSURER) peut assigner.
     *         Le dossier doit être au statut Declared.
     *         L'expert doit être enregistré dans RoleRegistry avec ROLE_EXPERT.
     *
     * @param  id      ID du dossier
     * @param  expert  Adresse wallet de l'expert
     */
    function assignExpert(uint256 id, address expert)
        external
        onlyRole(ROLE_INSURER)
        accidentExists(id)
        inStatus(id, AccidentStorage.Status.Declared)
    {
        require(
            roleRegistry.hasRole(expert, ROLE_EXPERT),
            "AccidentDApp: adresse non enregistree comme expert"
        );

        accidentStorage.setExpertAndStatus(id, expert);
        emit ExpertAssigned(id, expert, msg.sender);
    }

    /**
     * @notice Un expert s'auto-assigne sur un dossier déclaré sans expert.
     *         Permet à l'expert de prendre en charge directement un accident déclaré.
     *
     * @dev    Seul un expert enregistré (ROLE_EXPERT) peut s'auto-assigner.
     *         Le dossier doit être au statut Declared et sans expert assigné.
     *
     * @param  id  ID du dossier à prendre en charge
     */
    function assignSelf(uint256 id)
        external
        onlyRole(ROLE_EXPERT)
        accidentExists(id)
        inStatus(id, AccidentStorage.Status.Declared)
    {
        require(
            accidentStorage.getAccident(id).expert == address(0),
            "AccidentDApp: un expert est deja assigne"
        );

        accidentStorage.setExpertAndStatus(id, msg.sender);
        emit ExpertAssigned(id, msg.sender, address(0));
    }

    // ─────────────────────────────────────────────────────────────────────────
    // RAPPORT D'EXPERTISE
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice L'expert soumet son rapport d'expertise sur la blockchain.
     *
     * @dev    Seul l'expert spécifiquement assigné à CE dossier peut soumettre.
     *         Le dossier doit être au statut Verification.
     *
     * @param  id          ID du dossier expertisé
     * @param  reportHash  SHA-256 du rapport (64 chars hex)
     * @param  reportCID   CID IPFS du rapport
     */
    function submitReport(
        uint256         id,
        string calldata reportHash,
        string calldata reportCID
    )
        external
        accidentExists(id)
        inStatus(id, AccidentStorage.Status.Verification)
        validHash(reportHash)
    {
        require(
            accidentStorage.getAccident(id).expert == msg.sender,
            "AccidentDApp: not the assigned expert"
        );

        accidentStorage.submitReport(id, reportHash, reportCID);
        emit ReportSubmitted(id, msg.sender, reportHash, reportCID);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // VALIDATION / REJET PAR L'ASSUREUR
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice L'assureur valide le dossier après lecture du rapport d'expertise.
     *
     * @dev    Seul un assureur enregistré (ROLE_INSURER) peut valider.
     *         Le dossier doit être au statut Expertise (rapport soumis).
     *
     * @param  id  ID du dossier à valider
     */
    function validateAccident(uint256 id)
        external
        onlyRole(ROLE_INSURER)
        accidentExists(id)
        inStatus(id, AccidentStorage.Status.Expertise)
    {
        accidentStorage.validateAccident(id, msg.sender);
        emit AccidentValidated(id, msg.sender);
    }

    /**
     * @notice L'assureur rejette le dossier avec un motif obligatoire.
     *         Possible depuis Verification (sans rapport) ou Expertise (avec rapport).
     *
     * @dev    Le motif est émis dans l'événement — visible off-chain sans frais.
     *         Obligatoire pour assurer la transparence du rejet.
     *
     * @param  id      ID du dossier
     * @param  reason  Motif du rejet (non vide)
     */
    function rejectAccident(uint256 id, string calldata reason)
        external
        onlyRole(ROLE_INSURER)
        accidentExists(id)
    {
        AccidentStorage.Status currentStatus = accidentStorage.getStatus(id);
        require(
            currentStatus == AccidentStorage.Status.Expertise ||
            currentStatus == AccidentStorage.Status.Verification,
            "AccidentDApp: rejet impossible a ce stade"
        );
        require(bytes(reason).length > 0, "AccidentDApp: raison requise");

        accidentStorage.rejectAccident(id, msg.sender);
        emit AccidentRejected(id, msg.sender, reason);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // CLÔTURE DU DOSSIER
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice L'owner clôture définitivement un dossier validé (après indemnisation).
     *         Un dossier Closed est archivé — aucune action supplémentaire possible.
     *
     * @param  id  ID du dossier à clôturer
     */
    function closeAccident(uint256 id)
        external
        onlyOwner
        accidentExists(id)
        inStatus(id, AccidentStorage.Status.Validated)
    {
        accidentStorage.closeAccident(id);
        emit AccidentClosed(id);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // LECTURE — Délégation vers AccidentStorage (view — gratuites)
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice Retourne toutes les données d'un dossier d'accident.
     *         Le frontend n'a besoin que de l'adresse AccidentDApp pour lire.
     *
     * @param  id  ID du dossier
     */
    function getAccident(uint256 id)
        external
        view
        accidentExists(id)
        returns (AccidentStorage.Accident memory)
    {
        return accidentStorage.getAccident(id);
    }

    /**
     * @notice Retourne uniquement le statut d'un dossier (lecture légère).
     *
     * @param  id  ID du dossier
     */
    function getAccidentStatus(uint256 id)
        external
        view
        accidentExists(id)
        returns (AccidentStorage.Status)
    {
        return accidentStorage.getStatus(id);
    }

    /**
     * @notice Retourne le nombre total de dossiers déclarés.
     */
    function getAccidentCount() external view returns (uint256) {
        return accidentStorage.getAccidentCount();
    }
}

contracts/AccidentStorage.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  AccidentStorage
 * @notice Couche de stockage pur des dossiers d'accidents — aucune logique métier.
 *
 * @dev    Contrat indépendant suivant le pattern "Storage / Logic Separation".
 *
 *         Modèle d'accès :
 *         - Lecture (view) : publique — tout le monde peut lire
 *         - Écriture       : réservée au `authorizedController` (AccidentDApp)
 *
 *         Ce contrat peut être remplacé par une nouvelle version de la logique métier
 *         sans perdre les données historiques — il suffit de pointer le nouveau
 *         AccidentDApp vers ce même AccidentStorage.
 *
 *         Cycle de vie d'un dossier :
 *         Declared → Verification → Expertise → Validated / Rejected → Closed
 */
contract AccidentStorage {

    // ─────────────────────────────────────────────────────────────────────────
    // ÉNUMÉRATIONS
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @dev Représente l'état d'avancement d'un dossier d'accident.
     *      Déclaré ici afin que les autres contrats puissent importer ce type.
     */
    enum Status {
        Declared,     // 0 — Conducteur a soumis le constat
        Verification, // 1 — Expert assigné, en attente de son rapport
        Expertise,    // 2 — Rapport d'expertise soumis
        Validated,    // 3 — Assureur a validé (indemnisation en cours)
        Rejected,     // 4 — Assureur a rejeté (motif émis en événement)
        Closed        // 5 — Dossier clôturé et archivé
    }

    // ─────────────────────────────────────────────────────────────────────────
    // STRUCTURES
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @dev Structure principale d'un dossier d'accident.
     *      Les données sensibles (description, détails véhicule) sont stockées
     *      off-chain sur IPFS — seuls les hash SHA-256 et CID sont on-chain.
     */
    struct Accident {
        uint256 id;            // Identifiant unique auto-incrémenté (commence à 1)
        address driver;        // Wallet du conducteur déclarant
        address expert;        // Wallet de l'expert assigné (address(0) si aucun)
        address insurer;       // Wallet de l'assureur traitant (address(0) si aucun)
        string  evidenceHash;  // SHA-256 des preuves conducteur (64 chars hex)
        string  evidenceCID;   // CID IPFS des preuves conducteur
        string  reportHash;    // SHA-256 du rapport d'expertise (vide avant expertise)
        string  reportCID;     // CID IPFS du rapport d'expertise
        string  location;      // Lieu de l'accident
        uint256 timestamp;     // Horodatage de la déclaration (block.timestamp)
        Status  status;        // État actuel du dossier
        bool    driverSigned;  // true dès la déclaration (signature MetaMask implicite)
        bool    expertSigned;  // true après soumission du rapport
    }

    // ─────────────────────────────────────────────────────────────────────────
    // ÉTAT
    // ─────────────────────────────────────────────────────────────────────────

    /// @notice Adresse du déployeur (administrateur du registre de stockage)
    address public owner;

    /**
     * @notice Seul ce contrat peut écrire dans le stockage.
     *         Doit être défini après le déploiement de AccidentDApp via setController().
     */
    address public authorizedController;

    /// @notice Nombre total de dossiers (les IDs vont de 1 à accidentCount)
    uint256 public accidentCount;

    /// @dev Stockage principal : ID → Accident
    mapping(uint256 => Accident) private accidents;

    // ─────────────────────────────────────────────────────────────────────────
    // ÉVÉNEMENTS
    // ─────────────────────────────────────────────────────────────────────────

    /// @notice Émis quand le contrôleur autorisé est mis à jour
    event ControllerUpdated(address indexed oldController, address indexed newController);

    // ─────────────────────────────────────────────────────────────────────────
    // MODIFICATEURS
    // ─────────────────────────────────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "AccidentStorage: not owner");
        _;
    }

    /// @dev Toute écriture est réservée au contrat de logique métier (AccidentDApp)
    modifier onlyController() {
        require(
            msg.sender == authorizedController,
            "AccidentStorage: caller is not the authorized controller"
        );
        _;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // CONSTRUCTEUR
    // ─────────────────────────────────────────────────────────────────────────

    constructor() {
        owner = msg.sender;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // ADMINISTRATION
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice Autorise un contrat de logique métier à écrire dans ce stockage.
     *         Appelé par l'owner après le déploiement de AccidentDApp.
     *
     * @dev    Peut être mis à jour pour pointer vers une nouvelle version de la
     *         logique métier sans toucher aux données stockées.
     *
     * @param  controller  Adresse du contrat AccidentDApp à autoriser
     */
    function setController(address controller) external onlyOwner {
        require(controller != address(0), "AccidentStorage: zero address");
        emit ControllerUpdated(authorizedController, controller);
        authorizedController = controller;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // ÉCRITURE (réservée au contrôleur autorisé)
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice Crée un nouveau dossier d'accident.
     *         Appelé par AccidentDApp.declareAccident().
     *
     * @param  driver        Wallet du conducteur
     * @param  evidenceHash  SHA-256 des preuves (64 chars hex)
     * @param  evidenceCID   CID IPFS des preuves
     * @param  location      Lieu de l'accident
     * @return               ID du dossier créé
     */
    function createAccident(
        address        driver,
        string calldata evidenceHash,
        string calldata evidenceCID,
        string calldata location
    ) external onlyController returns (uint256) {
        accidentCount++;

        accidents[accidentCount] = Accident({
            id:           accidentCount,
            driver:       driver,
            expert:       address(0),
            insurer:      address(0),
            evidenceHash: evidenceHash,
            evidenceCID:  evidenceCID,
            reportHash:   "",
            reportCID:    "",
            location:     location,
            timestamp:    block.timestamp,
            status:       Status.Declared,
            driverSigned: true,
            expertSigned: false
        });

        return accidentCount;
    }

    /**
     * @notice Assigne un expert à un dossier et passe son statut à Verification.
     * @param  id      ID du dossier
     * @param  expert  Wallet de l'expert
     */
    function setExpertAndStatus(uint256 id, address expert) external onlyController {
        accidents[id].expert = expert;
        accidents[id].status = Status.Verification;
    }

    /**
     * @notice Enregistre le rapport de l'expert et certifie sa signature.
     * @param  id          ID du dossier
     * @param  reportHash  SHA-256 du rapport
     * @param  reportCID   CID IPFS du rapport
     */
    function submitReport(
        uint256         id,
        string calldata reportHash,
        string calldata reportCID
    ) external onlyController {
        accidents[id].reportHash   = reportHash;
        accidents[id].reportCID    = reportCID;
        accidents[id].status       = Status.Expertise;
        accidents[id].expertSigned = true;
    }

    /**
     * @notice Valide un dossier : enregistre l'assureur et passe à Validated.
     * @param  id      ID du dossier
     * @param  insurer Wallet de l'assureur validant
     */
    function validateAccident(uint256 id, address insurer) external onlyController {
        accidents[id].insurer = insurer;
        accidents[id].status  = Status.Validated;
    }

    /**
     * @notice Rejette un dossier : enregistre l'assureur et passe à Rejected.
     * @param  id      ID du dossier
     * @param  insurer Wallet de l'assureur rejetant
     */
    function rejectAccident(uint256 id, address insurer) external onlyController {
        accidents[id].insurer = insurer;
        accidents[id].status  = Status.Rejected;
    }

    /**
     * @notice Clôture définitivement un dossier validé.
     * @param  id  ID du dossier
     */
    function closeAccident(uint256 id) external onlyController {
        accidents[id].status = Status.Closed;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // LECTURE (view — publique, sans gas)
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice Retourne la structure complète d'un dossier.
     * @param  id  ID du dossier (entre 1 et accidentCount)
     */
    function getAccident(uint256 id) external view returns (Accident memory) {
        return accidents[id];
    }

    /**
     * @notice Retourne uniquement le statut d'un dossier (lecture légère).
     * @param  id  ID du dossier
     */
    function getStatus(uint256 id) external view returns (Status) {
        return accidents[id].status;
    }

    /**
     * @notice Retourne le nombre total de dossiers déclarés.
     */
    function getAccidentCount() external view returns (uint256) {
        return accidentCount;
    }

    /**
     * @notice Vérifie qu'un ID de dossier est valide (entre 1 et accidentCount).
     * @param  id  ID à vérifier
     */
    function exists(uint256 id) external view returns (bool) {
        return id > 0 && id <= accidentCount;
    }
}

contracts/RoleRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title  RoleRegistry
 * @notice Gestion décentralisée des rôles (auto-enregistrement via wallet).
 *
 * @dev    Contrat indépendant — aucune dépendance vers la logique métier.
 *         Peut être réutilisé par plusieurs contrats de logique métier.
 *
 *         Modèle de sécurité :
 *         - Chaque wallet s'enregistre une seule fois avec un rôle
 *         - L'owner peut révoquer un acteur sans effacer son rôle (auditabilité)
 *         - `hasRole()` est la fonction centrale utilisée par le contrat orchestrateur
 */
contract RoleRegistry {

    // ─────────────────────────────────────────────────────────────────────────
    // CONSTANTES DE RÔLES
    // ─────────────────────────────────────────────────────────────────────────

    /// @dev Hash keccak256 de "DRIVER" — comparaison O(1), résistante aux collisions
    bytes32 public constant ROLE_DRIVER  = keccak256("DRIVER");

    /// @dev Hash keccak256 de "EXPERT"
    bytes32 public constant ROLE_EXPERT  = keccak256("EXPERT");

    /// @dev Hash keccak256 de "INSURER"
    bytes32 public constant ROLE_INSURER = keccak256("INSURER");

    // ─────────────────────────────────────────────────────────────────────────
    // ÉTAT
    // ─────────────────────────────────────────────────────────────────────────

    /// @notice Adresse du déployeur (administrateur)
    address public owner;

    /// @dev Rôle de chaque acteur : adresse → bytes32
    mapping(address => bytes32) private actorRoles;

    /// @dev Statut actif de chaque acteur (false = révoqué)
    mapping(address => bool)    private activeActors;

    // ─────────────────────────────────────────────────────────────────────────
    // ÉVÉNEMENTS
    // ─────────────────────────────────────────────────────────────────────────

    /// @notice Émis quand un wallet s'enregistre avec un rôle
    event RoleRegistered(address indexed actor, bytes32 indexed role);

    /// @notice Émis quand l'owner révoque un acteur
    event RoleRevoked(address indexed actor);

    // ─────────────────────────────────────────────────────────────────────────
    // MODIFICATEURS
    // ─────────────────────────────────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "RoleRegistry: not owner");
        _;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // CONSTRUCTEUR
    // ─────────────────────────────────────────────────────────────────────────

    constructor() {
        owner = msg.sender;
    }

    // ─────────────────────────────────────────────────────────────────────────
    // AUTO-ENREGISTREMENT (DApp — sans backend)
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice Permet à n'importe quel wallet de s'enregistrer avec un rôle.
     *         msg.sender est automatiquement l'adresse enregistrée.
     *
     * @dev    Un wallet ne peut s'enregistrer qu'une seule fois.
     *         Un acteur révoqué ne peut pas se ré-enregistrer avec la même adresse.
     *
     * @param  role  Le rôle souhaité : ROLE_DRIVER | ROLE_EXPERT | ROLE_INSURER
     */
    function register(bytes32 role) external {
        require(
            role == ROLE_DRIVER || role == ROLE_EXPERT || role == ROLE_INSURER,
            "RoleRegistry: role inconnu"
        );
        require(!activeActors[msg.sender], "RoleRegistry: deja enregistre");

        actorRoles[msg.sender]   = role;
        activeActors[msg.sender] = true;

        emit RoleRegistered(msg.sender, role);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // ADMINISTRATION
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice Révoque un acteur enregistré (fraude, erreur, fin de contrat).
     *         L'acteur révoqué ne peut plus effectuer d'actions sur les contrats
     *         qui s'appuient sur ce registre.
     *
     * @dev    Le rôle n'est pas effacé — il reste consultable pour l'audit.
     *         Seul l'owner du registre peut révoquer.
     *
     * @param  actor  Adresse wallet à révoquer
     */
    function revokeRole(address actor) external onlyOwner {
        activeActors[actor] = false;
        emit RoleRevoked(actor);
    }

    // ─────────────────────────────────────────────────────────────────────────
    // LECTURE
    // ─────────────────────────────────────────────────────────────────────────

    /**
     * @notice Retourne le rôle (bytes32) d'une adresse.
     *         Retourne bytes32(0) si l'adresse n'est jamais enregistrée.
     */
    function getRole(address actor) external view returns (bytes32) {
        return actorRoles[actor];
    }

    /**
     * @notice Retourne true si l'acteur est enregistré et non révoqué.
     */
    function isActive(address actor) external view returns (bool) {
        return activeActors[actor];
    }

    /**
     * @notice Vérifie qu'un acteur est actif ET possède exactement le rôle attendu.
     *         Fonction centrale utilisée par le contrat orchestrateur AccidentDApp.
     *
     * @param  actor  Adresse à vérifier
     * @param  role   Rôle attendu (ex. ROLE_DRIVER)
     * @return        true si actif et rôle correspond
     */
    function hasRole(address actor, bytes32 role) external view returns (bool) {
        return activeActors[actor] && actorRoles[actor] == role;
    }
}

